import { Injectable, inject, signal, DestroyRef } from '@angular/core';
import { of, tap, catchError } from 'rxjs';

import { AppInstallationService } from './app-installation.service';
import { ClientDataService } from '../../clients/services/client-data.service';
import { ModalFormService } from '../../../shared/services/forms/modal-form.service';
import { ModalListFormComponent } from '../../../shared/components/forms/modal-list-form/modal-list-form.component';
import {
  createTextAreaField,
  createTextField,
  createNumberField,
} from '../../../shared/models/form-field.model';
import { AppDefinition } from '../models/app-store.models';
import { isNullOrUndefined } from '../../../shared/utils';

/**
 * Facade service that centralises install, uninstall, and toggle-enabled logic.
 * Consumers inject this service and bind to its state signals instead of
 * duplicating the orchestration in each component.
 */
@Injectable({ providedIn: 'root' })
export class AppInstallFacadeService {
  private readonly appInstallationService = inject(AppInstallationService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly modalFormService = inject(ModalFormService);

  // ── UI state ────────────────────────────────────────────────────────────────
  readonly isPerformingAction = signal(false);
  readonly error = signal<string | null>(null);
  readonly isTogglingEnabled = signal(false);
  readonly toggleEnabledError = signal<string | null>(null);

  // ── Install ─────────────────────────────────────────────────────────────────

  /**
   * Install an app. Opens a config modal for external (appSidebar) apps;
   * performs a direct install for all others.
   */
  installApp(
    app: AppDefinition,
    destroyRef: DestroyRef,
    onSuccess?: () => void,
  ): void {
    const clientId = this.clientDataService.getSelectedClient()?.id;
    if (isNullOrUndefined(clientId)) return;

    const isExternalApp = app.integrationPoints?.some(
      (point) => point.screenId === 'appSidebar',
    );

    if (isExternalApp) {
      this.openInstallConfigModal(app, clientId, destroyRef, onSuccess);
    } else {
      this.performInstallation(app.id, clientId, {}, onSuccess);
    }
  }

  private openInstallConfigModal(
    app: AppDefinition,
    clientId: string,
    destroyRef: DestroyRef,
    onSuccess?: () => void,
  ): void {
    const dummyField = createTextAreaField('dummy', 'dummy', undefined);

    this.modalFormService
      .openListItemModal<Record<string, string | number>>({
        modalConfig: {
          modalComponent: ModalListFormComponent,
          modalTitle: 'Configure App Sidebar Installation',
          subHeader:
            'Customize how this app appears in the sidebar external tabs',
          modalFields: [
            createTextField('icon', 'Sidebar Icon', 'browser', {
              placeholder: 'browser',
              hint: 'Material icon name or URL for the sidebar tab',
            }),
            createTextField('section', 'Sidebar Section', 'Apps', {
              placeholder: 'Apps',
              hint: 'UI section where the sidebar tab will appear',
            }),
            createNumberField('order', 'Sidebar Display Order', 0, {
              hint: 'Lower numbers appear first in the sidebar',
            }),
          ],
          onSubmit: (data, ref) => {
            this.error.set(null);
            this.isPerformingAction.set(true);

            const config = {
              appSidebar: {
                icon: data['icon'] as string,
                section: data['section'] as string,
                order: data['order'] as number,
              },
            };

            return new Promise((resolve) => {
              this.appInstallationService
                .installExternalApp(app.id, clientId, config)
                .pipe(
                  tap(async () => {
                    this.error.set(null);
                    try {
                      await this.clientDataService.setSelectedClientById(
                        clientId,
                      );
                    } catch (e) {
                      console.warn('Failed to refresh client data:', e);
                    }
                    this.isPerformingAction.set(false);
                    onSuccess?.();
                    ref.close();
                    resolve(true);
                  }),
                  catchError((err) => {
                    console.error('App installation error:', err);
                    this.error.set(
                      'Could not install the app. Please try again.',
                    );
                    this.isPerformingAction.set(false);
                    resolve(false);
                    return of(null);
                  }),
                )
                .subscribe();
            });
          },
        },
        itemData: { icon: 'browser', section: 'Apps', order: 0 },
        destroyRef,
        field: dummyField,
      })
      .subscribe();
  }

  private performInstallation(
    appId: string,
    clientId: string,
    configuration: Record<string, unknown>,
    onSuccess?: () => void,
  ): void {
    this.error.set(null);
    this.isPerformingAction.set(true);

    this.appInstallationService
      .installApp(appId, clientId, configuration)
      .pipe(
        tap(() => {
          this.error.set(null);
          onSuccess?.();
        }),
        catchError((err) => {
          console.error('App installation error:', err);
          this.error.set('Could not install the app. Please try again.');
          return of(null);
        }),
      )
      .subscribe({ complete: () => this.isPerformingAction.set(false) });
  }

  // ── Uninstall ────────────────────────────────────────────────────────────────

  /**
   * Uninstall an app by installation ID.
   * Pass `isExternalApp: true` for appSidebar apps so the correct endpoint is used.
   */
  uninstallApp(
    installationId: string,
    isExternalApp = false,
    onSuccess?: () => void,
  ): void {
    const clientId = this.clientDataService.getSelectedClient()?.id;
    if (isNullOrUndefined(clientId)) return;

    this.error.set(null);
    this.isPerformingAction.set(true);

    const uninstall$ = isExternalApp
      ? this.appInstallationService.uninstallExternalApp(
          installationId,
          clientId,
        )
      : this.appInstallationService.uninstallApp(installationId, clientId);

    uninstall$
      .pipe(
        tap(async () => {
          this.error.set(null);
          if (isExternalApp) {
            try {
              await this.clientDataService.setSelectedClientById(clientId);
            } catch (e) {
              console.warn('Failed to refresh client data:', e);
            }
          }
          onSuccess?.();
        }),
        catchError((err) => {
          console.error('App uninstallation error:', err);
          this.error.set('Could not uninstall the app. Please try again.');
          return of(null);
        }),
      )
      .subscribe({ complete: () => this.isPerformingAction.set(false) });
  }

  // ── Toggle enabled ───────────────────────────────────────────────────────────

  toggleEnabled(
    installationId: string,
    currentValue: boolean,
    onSuccess?: () => void,
  ): void {
    const clientId = this.clientDataService.getSelectedClient()?.id;
    if (isNullOrUndefined(clientId)) return;

    this.toggleEnabledError.set(null);
    this.isTogglingEnabled.set(true);

    this.appInstallationService
      .setEnabled(installationId, clientId, !currentValue)
      .pipe(
        tap(() => onSuccess?.()),
        catchError((err) => {
          console.error('Toggle enabled error:', err);
          this.toggleEnabledError.set(
            'Could not update app status. Please try again.',
          );
          return of(null);
        }),
      )
      .subscribe({ complete: () => this.isTogglingEnabled.set(false) });
  }
}
